package main

import (
	"fmt"
	"github.com/go-playground/validator/v10"
)

type Data struct {
	Name    string
	Email   string
	Details *Details
}

type Details struct {
	FamilyMembers *FamilyMembers
	Salary        string
}

type FamilyMembers struct {
	FatherName string
	MotherName string
}

type Data2 struct {
	Name string
	Age  uint32
}

var validate = validator.New()

func main() {
	validateStruct()
	// output
	// Key: 'Data2.Name' Error:Field validation for 'Name' failed on the 'min' tag
	// Key: 'Data2.Age' Error:Field validation for 'Age' failed on the 'max' tag

	validateStructNested()
	// output
	// Key: 'Data.Name' Error:Field validation for 'Name' failed on the 'max' tag
	// Key: 'Data.Details.FamilyMembers' Error:Field validation for 'FamilyMembers' failed on the 'required' tag
}

func validateStruct() {
	data := Data2{
		Name: "leo",
		Age:  1000,
	}

	rules := map[string]string{
		"Name": "min=4,max=6",
		"Age":  "min=4,max=6",
	}

	validate.RegisterStructValidationMapRules(rules, Data2{})

	err := validate.Struct(data)
	fmt.Println(err)
	fmt.Println()
}

func validateStructNested() {
	data := Data{
		Name:  "11sdfddd111",
		Email: "zytel3301@mail.com",
		Details: &Details{
			Salary: "1000",
		},
	}

	rules1 := map[string]string{
		"Name":    "min=4,max=6",
		"Email":   "required,email",
		"Details": "required",
	}

	rules2 := map[string]string{
		"Salary":        "number",
		"FamilyMembers": "required",
	}

	rules3 := map[string]string{
		"FatherName": "required,min=4,max=32",
		"MotherName": "required,min=4,max=32",
	}

	validate.RegisterStructValidationMapRules(rules1, Data{})
	validate.RegisterStructValidationMapRules(rules2, Details{})
	validate.RegisterStructValidationMapRules(rules3, FamilyMembers{})
	err := validate.Struct(data)

	fmt.Println(err)
}

package redis

import (
	"context"
	"sync"
	"sync/atomic"
)

func (c *ClusterClient) DBSize(ctx context.Context) *IntCmd {
	cmd := NewIntCmd(ctx, "dbsize")
	_ = c.withProcessHook(ctx, cmd, func(ctx context.Context, _ Cmder) error {
		var size int64
		err := c.ForEachMaster(ctx, func(ctx context.Context, master *Client) error {
			n, err := master.DBSize(ctx).Result()
			if err != nil {
				return err
			}
			atomic.AddInt64(&size, n)
			return nil
		})
		if err != nil {
			cmd.SetErr(err)
		} else {
			cmd.val = size
		}
		return nil
	})
	return cmd
}

func (c *ClusterClient) ScriptLoad(ctx context.Context, script string) *StringCmd {
	cmd := NewStringCmd(ctx, "script", "load", script)
	_ = c.withProcessHook(ctx, cmd, func(ctx context.Context, _ Cmder) error {
		var mu sync.Mutex
		err := c.ForEachShard(ctx, func(ctx context.Context, shard *Client) error {
			val, err := shard.ScriptLoad(ctx, script).Result()
			if err != nil {
				return err
			}

			mu.Lock()
			if cmd.Val() == "" {
				cmd.val = val
			}
			mu.Unlock()

			return nil
		})
		if err != nil {
			cmd.SetErr(err)
		}
		return nil
	})
	return cmd
}

func (c *ClusterClient) ScriptFlush(ctx context.Context) *StatusCmd {
	cmd := NewStatusCmd(ctx, "script", "flush")
	_ = c.withProcessHook(ctx, cmd, func(ctx context.Context, _ Cmder) error {
		err := c.ForEachShard(ctx, func(ctx context.Context, shard *Client) error {
			return shard.ScriptFlush(ctx).Err()
		})
		if err != nil {
			cmd.SetErr(err)
		}
		return nil
	})
	return cmd
}

func (c *ClusterClient) ScriptExists(ctx context.Context, hashes ...string) *BoolSliceCmd {
	args := make([]interface{}, 2+len(hashes))
	args[0] = "script"
	args[1] = "exists"
	for i, hash := range hashes {
		args[2+i] = hash
	}
	cmd := NewBoolSliceCmd(ctx, args...)

	result := make([]bool, len(hashes))
	for i := range result {
		result[i] = true
	}

	_ = c.withProcessHook(ctx, cmd, func(ctx context.Context, _ Cmder) error {
		var mu sync.Mutex
		err := c.ForEachShard(ctx, func(ctx context.Context, shard *Client) error {
			val, err := shard.ScriptExists(ctx, hashes...).Result()
			if err != nil {
				return err
			}

			mu.Lock()
			for i, v := range val {
				result[i] = result[i] && v
			}
			mu.Unlock()

			return nil
		})
		if err != nil {
			cmd.SetErr(err)
		} else {
			cmd.val = result
		}
		return nil
	})
	return cmd
}

package main

import (
	"context"

	"github.com/davecgh/go-spew/spew"

	"github.com/redis/go-redis/v9"
)

type Model struct {
	Str1    string   `redis:"str1"`
	Str2    string   `redis:"str2"`
	Str3    *string  `redis:"str3"`
	Bytes   []byte   `redis:"bytes"`
	Int     int      `redis:"int"`
	Int2    *int     `redis:"int2"`
	Bool    bool     `redis:"bool"`
	Bool2   *bool    `redis:"bool2"`
	Ignored struct{} `redis:"-"`
}

func main() {
	ctx := context.Background()

	rdb := redis.NewClient(&redis.Options{
		Addr: ":6379",
	})
	_ = rdb.FlushDB(ctx).Err()

	// Set some fields.
	if _, err := rdb.Pipelined(ctx, func(rdb redis.Pipeliner) error {
		rdb.HSet(ctx, "key", "str1", "hello")
		rdb.HSet(ctx, "key", "str2", "world")
		rdb.HSet(ctx, "key", "str3", "")
		rdb.HSet(ctx, "key", "int", 123)
		rdb.HSet(ctx, "key", "int2", 0)
		rdb.HSet(ctx, "key", "bool", 1)
		rdb.HSet(ctx, "key", "bool2", 0)
		rdb.HSet(ctx, "key", "bytes", []byte("this is bytes !"))
		return nil
	}); err != nil {
		panic(err)
	}

	var model1, model2 Model

	// Scan all fields into the model.
	if err := rdb.HGetAll(ctx, "key").Scan(&model1); err != nil {
		panic(err)
	}

	// Or scan a subset of the fields.
	if err := rdb.HMGet(ctx, "key", "str1", "int").Scan(&model2); err != nil {
		panic(err)
	}

	spew.Dump(model1)
	// Output:
	// (main.Model) {
	// 	Str1: (string) (len=5) "hello",
	// 	Str2: (string) (len=5) "world",
	// 	Bytes: ([]uint8) (len=15 cap=16) {
	// 	 00000000  74 68 69 73 20 69 73 20  62 79 74 65 73 20 21     |this is bytes !|
	// 	},
	// 	Int: (int) 123,
	// 	Bool: (bool) true,
	// 	Ignored: (struct {}) {
	// 	}
	// }

	spew.Dump(model2)
	// Output:
	// (main.Model) {
	// 	Str1: (string) (len=5) "hello",
	// 	Str2: (string) "",
	// 	Bytes: ([]uint8) <nil>,
	// 	Int: (int) 123,
	// 	Bool: (bool) false,
	// 	Ignored: (struct {}) {
	// 	}
	// }
}

package main

import (
	"context"
	"fmt"
	"log"
	"sync"
	"time"

	"go.opentelemetry.io/otel"
	"go.opentelemetry.io/otel/codes"

	"github.com/uptrace/uptrace-go/uptrace"

	"github.com/redis/go-redis/extra/redisotel/v9"
	"github.com/redis/go-redis/v9"
)

var tracer = otel.Tracer("github.com/redis/go-redis/example/otel")

func main() {
	ctx := context.Background()

	uptrace.ConfigureOpentelemetry(
		// copy your project DSN here or use UPTRACE_DSN env var
		uptrace.WithDSN("http://project1_secret@localhost:14318/2?grpc=14317"),

		uptrace.WithServiceName("myservice"),
		uptrace.WithServiceVersion("v1.0.0"),
	)
	defer uptrace.Shutdown(ctx)

	rdb := redis.NewClient(&redis.Options{
		Addr: ":6379",
	})
	if err := redisotel.InstrumentTracing(rdb); err != nil {
		panic(err)
	}
	if err := redisotel.InstrumentMetrics(rdb); err != nil {
		panic(err)
	}

	for i := 0; i < 1e6; i++ {
		ctx, rootSpan := tracer.Start(ctx, "handleRequest")

		if err := handleRequest(ctx, rdb); err != nil {
			rootSpan.RecordError(err)
			rootSpan.SetStatus(codes.Error, err.Error())
		}

		rootSpan.End()

		if i == 0 {
			fmt.Printf("view trace: %s\n", uptrace.TraceURL(rootSpan))
		}

		time.Sleep(time.Second)
	}
}

func handleRequest(ctx context.Context, rdb *redis.Client) error {
	if err := rdb.Set(ctx, "First value", "value_1", 0).Err(); err != nil {
		return err
	}
	if err := rdb.Set(ctx, "Second value", "value_2", 0).Err(); err != nil {
		return err
	}

	var group sync.WaitGroup

	for i := 0; i < 20; i++ {
		group.Add(1)
		go func() {
			defer group.Done()
			val := rdb.Get(ctx, "Second value").Val()
			if val != "value_2" {
				log.Printf("%q != %q", val, "value_2")
			}
		}()
	}

	group.Wait()

	if err := rdb.Del(ctx, "First value").Err(); err != nil {
		return err
	}
	if err := rdb.Del(ctx, "Second value").Err(); err != nil {
		return err
	}

	return nil
}

package logrus

import (
	"strings"
	"sync"
)

const (
	ansiReset  = "\x1b[0m"  // reset attributes
	ansiRed    = "\x1b[31m" // red
	ansiYellow = "\x1b[33m" // yellow
	ansiCyan   = "\x1b[36m" // cyan
	ansiWhite  = "\x1b[37m" // white (light gray)
)

type lvlPrefix struct {
	full      string
	truncated string
	padded    string
}

func colorize(level Level, s string) string {
	color := ansiCyan
	switch level {
	case DebugLevel, TraceLevel:
		color = ansiWhite
	case WarnLevel:
		color = ansiYellow
	case ErrorLevel, FatalLevel, PanicLevel:
		color = ansiRed
	case InfoLevel:
		color = ansiCyan
	}
	return color + s + ansiReset
}

func formatLevel(level Level, disableTrunc, pad bool, maxLen int) string {
	upper := strings.ToUpper(level.String())

	if pad && maxLen > len(upper) {
		upper += strings.Repeat(" ", maxLen-len(upper))
	}

	if !pad && !disableTrunc && len(upper) > 4 {
		upper = upper[:4]
	}

	return colorize(level, upper)
}

var levelPrefixOnce = sync.OnceValues(func() (map[Level]lvlPrefix, lvlPrefix) {
	var maxLevel Level
	maxLen := 0
	for _, lvl := range AllLevels {
		if lvl > maxLevel {
			maxLevel = lvl
		}
		if l := len(lvl.String()); l > maxLen {
			maxLen = l
		}
	}

	prefix := make(map[Level]lvlPrefix, len(AllLevels))
	for _, lvl := range AllLevels {
		prefix[lvl] = lvlPrefix{
			full:      formatLevel(lvl, true, false, maxLen),
			truncated: formatLevel(lvl, false, false, maxLen),
			padded:    formatLevel(lvl, true, true, maxLen),
		}
	}

	unknownLevel := maxLevel + 1
	unknown := lvlPrefix{
		full:      formatLevel(unknownLevel, true, false, maxLen),
		truncated: formatLevel(unknownLevel, false, false, maxLen),
		padded:    formatLevel(unknownLevel, true, true, maxLen),
	}

	return prefix, unknown
})

func levelPrefix(level Level, disableTrunc, pad bool) string {
	prefix, unknown := levelPrefixOnce()

	p, ok := prefix[level]
	if !ok {
		p = unknown
	}

	switch {
	case pad:
		return p.padded
	case !disableTrunc:
		return p.truncated
	default:
		return p.full
	}
}
